selector_to_html = {"a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1.5 </span>End Effector Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p>The end-effector control module currently supports:</p>", "a[href=\"#id3\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Hand Control Topics<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"../../example/Cpp.html#cpp-hand-control\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.4 </span>Gripper Control<a class=\"headerlink\" href=\"#cpp-hand-control\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses hand_control. By publishing messages to the topic <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/joint/hand/command</span></code>, you can control the movement of the gripper.</strong></p>", "a[href=\"#tbl-hand-order\"]": "<table class=\"docutils align-default\" id=\"tbl-hand-order\">\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p>Hand Type</p></th>\n<th class=\"head\"><p>Array Length</p></th>\n<th class=\"head\"><p>Order</p></th>\n<th class=\"head\"><p>Additional Info</p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p>Gripper OmniPicker</p></td>\n<td><p>1</p></td>\n<td><p>N/A</p></td>\n<td><p>N/A</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Dexterous Hand OmniHand</p></td>\n<td><p>10</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">ThumbRoll</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">ThumbAbAd</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">ThumbMCP</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">IndexAbAd</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">IndexPIP</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">MiddlePIP</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">RingAbAd</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">RingPIP</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">PinkyAbAd</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">PinkyPIP</span></code></p></td>\n<td><p>Currently only supports configuring all joints at once; arranged in active joint index order</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"../../example/Python.html#py-joint-control\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Robot joint control example<a class=\"headerlink\" href=\"#py-joint-control\" title=\"Link to this heading\">\uf0c1</a></h3><p>This example shows how to use ROS2 and the Ruckig library to control robot joints. The example implements the following features:</p>", "a[href=\"#id6\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Programming Examples<a class=\"headerlink\" href=\"#id6\" title=\"Link to this heading\">\uf0c1</a></h2><p>For detailed programming examples and explanations, refer to:</p>", "a[href=\"#id4\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Hand Status Topics<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id5\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Hand Type Query Service<a class=\"headerlink\" href=\"#id5\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id7\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Safety Notes<a class=\"headerlink\" href=\"#id7\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Hand Control Features<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
